import okhttp3.Interceptor
import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.Response
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory

object NetworkModule {

    private const val BASE_URL = "https://api.example.com/"

    fun provideRetrofit(token: String, environment: String): Retrofit {
        return Retrofit.Builder()
            .baseUrl(getBaseUrl(environment))
            .addConverterFactory(GsonConverterFactory.create())
            .client(provideOkHttpClient(token))
            .build()
    }

    private fun getBaseUrl(environment: String): String {
        return when (environment) {
            "dev" -> BASE_URL + "dev/"
            "staging" -> BASE_URL + "staging/"
            else -> BASE_URL
        }
    }

    private fun provideOkHttpClient(token: String): OkHttpClient {
        return OkHttpClient.Builder().addInterceptor(AuthInterceptor(token)).build()
    }

    class AuthInterceptor(private val token: String) : Interceptor {
        override fun intercept(chain: Interceptor.Chain): Response {
            val original: Request = chain.request()
            val requestBuilder: Request.Builder = original.newBuilder()
                .addHeader("Authorization", "Bearer $token")
                .method(original.method, original.body)

            val request: Request = requestBuilder.build()
            return chain.proceed(request)
        }
    }
}